#include <stdio.h>
#include <stdlib.h>

long multiplos_de_onze[] = {
    0,
    1,
    11,
    111,
    1111,
    11111,
    111111,
    1111111,
    11111111,
    111111111,
    1111111111,
    11111111111,
    111111111111,
    1111111111111,
    11111111111111,
    111111111111111,
    1111111111111111,
    11111111111111111,
};

long procura_onze(long n, int i) {
    long divisao = n / multiplos_de_onze[i];
    long resto = n % multiplos_de_onze[i];
    if (resto == 0) {
        return divisao * i;
    } else {
        long opcao1 = i + procura_onze(multiplos_de_onze[i] - resto, i - 1);
        long opcao2 = procura_onze(resto, i - 1);
        return divisao * i + (opcao1 < opcao2 ? opcao1 : opcao2);
    }
}

void divide() {
    long n;
    scanf("%ld", &n);
    long m = procura_onze(n, 16);
    printf("%ld\n", m);
}

int main() {
    divide();
    return 0;
}
